var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님! 제 3, 제 4 군집이 계속 접근 중입니다!","JPN":"大佐！　第3、第4の群れがどんどん接近してきています！","ENG":"Colonel! Third and fourth hordes approaching!","TWN":"上校！第3群，第4群還在繼續靠近！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"함포를 통한 지원은 이미 한계입니다! 어서 그곳에서 이탈하십시오!","JPN":"艦砲を含めた支援火力はもう限界です！　直ちにそこを離脱してください！","ENG":"The cannons have reached their limit! Get out of there!","TWN":"艦炮的支援已經達到極限了！請快點離開那個地方！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"그래, 슬슬 막차 시간인가?","JPN":"ああ、そろそろ終電か？","ENG":"Ahh, is it the last train already?","TWN":"嗯，快到末班車時間了嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"실비아, 방학 숙제는 아직 멀었나? 곧 마감 시간이야.","JPN":"シルビア、夏休みの課題はまだか？　じきにタイムアウトだぞ。","ENG":"Sylvia, are you done with your homework? The deadline's coming up.","TWN":"希爾維亞，假期作業做完了嗎？馬上就到交作業的時間了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"기다려 봐, 바보야! 거의 다……!","JPN":"まってよ、ばか！　あともうちょっとで……！","ENG":"Wait a sec, dummy! I'm almost–!","TWN":"等等，傻瓜！就快……！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"엎드려, 아가씨!","JPN":"伏せろ、お嬢ちゃん！","ENG":"Duck, Missy!","TWN":"趴下，小姐！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"치, 침식체가 등대에 들이받았어……?","JPN":"し、侵食体が灯台に体当たりした……？","ENG":"Th-the C.O. rammed into the Lighthouse...?","TWN":"侵，侵蝕體在撞擊燈塔……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"조심해. 조금만 늦게 잡아당겼으면 그대로 납작해질 뻔했잖아.","JPN":"気を付けろ。引っ張るのが少し遅かったら、あのままぺちゃんこになっていたぞ。","ENG":"Be careful. You would've been crushed if I pulled you out late.","TWN":"小心。我拉你要是慢了些，你就被壓扁了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"이봐, 지금 그게 중요한 게 아닌 것 같은데.","JPN":"おい、今はそれよりこっちの方が重要なんじゃないか。","ENG":"Hey, that's not what's important right now.","TWN":"喂，現在那個好像不重要吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"오, 그러게. 등대의 상태가 이상해. 신호가 더 강해졌어.","JPN":"おう、そうだな。灯台の様子がおかしい。信号がさらに強くなった。","ENG":"Oh, right. The Lighthouse is acting strange. The signal's even stronger.","TWN":"是啊。燈塔的狀態很奇怪。訊號反而變強了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"……너무 세게 맞아서 화났나?","JPN":"……体当たりが強すぎて、怒ったのか？","ENG":"...Is it angry from getting hit?","TWN":"……因為被打了所以生氣了？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이런…… 제기랄!","JPN":"この……くそ！","ENG":"This... Goddammit!","TWN":"可惡……該死的！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다들 뛰어! 방금 전 충돌로 폭주하는 거다! 저대로는 오래 못 버텨!","JPN":"全員走れ！　今の衝突で暴走し始めたぞ！　あの様子じゃ長くは持たねぇ！","ENG":"Everyone, run! It's going to blow up from the impact! It's not going to hold up!","TWN":"大家跳！剛才的碰撞會讓它爆炸的！這樣下去堅持不了多久！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"자, 잠깐! 아저씨! 저게 없으면 우린 영영 허수 공간에 갇혀 있어야 한다고!","JPN":"ちょ、ちょつと！　おじさん！　あれがないとアタシたちは永遠に虚数空間に閉じ込められちゃうのよ？！","ENG":"W-wait! We're going to be stuck in the imaginary space forever without that!","TWN":"等，等等！大叔！要是沒有那個，我們就得永遠被關在虛數空間了！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런 걱정은 일단 살고 나서 해!","JPN":"そんな心配は助かってからにしろ！","ENG":"Run first, worry later!","TWN":"先活下來再擔心那些吧！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"저 빛기둥은…… 설마 등대 쪽에 문제가 생긴 건가?","JPN":"あの光の柱は……まさか灯台に問題が起きたのか？","ENG":"That pillar of light... Is there an issue with the Lighthouse?","TWN":"那道光束……難道是燈塔那頭出了什麼問題？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"대령님, 침식체들의 움직임도 달라졌어요.","JPN":"大佐、侵食体の動きも変化しました。","ENG":"Colonel, the C.O.s are acting different too.","TWN":"上校，侵蝕體的動向也變了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"갑자기 왜 저래? 바로 앞에 있는데도 두리번거리는데?","JPN":"いきなりどうしたんだ？　キョロキョロして、すぐ目の前の灯台もわからないみたいだ。","ENG":"What's with them? We're right in front of them, but they look lost.","TWN":"怎麼會突然這樣？我們明明就在眼前，卻不攻擊了？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"……등대의 신호가 사라졌다는 뜻이겠지.","JPN":"……灯台の信号が消えたんだろうね。","ENG":"...It means that the signals from the Lighthouse disappeared.","TWN":"……應該是燈塔的訊號消失了吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"이 침식체들은 오감이 아니라 특정 신호로 대상을 감지하는 것 같거든. 심해어처럼.","JPN":"この侵食体どもは五感ではなく、特定の信号によって相手を感知するみたいだし。深海魚のようにね。","ENG":"Seems like these C.O.s detect targets through certain signals rather than the normal senses. Like deep-sea fish.","TWN":"這些侵蝕體好像是靠特定訊號而不是五感感應目標的，就像深海魚一樣。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"콜록, 콜록……!","JPN":"ゴホッ、ゴホッ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳……！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"무슨 생각이야, 아저씨?! 등대 없이는 좀 더 늦게 죽을 뿐이라고!","JPN":"どういうつもりなの、おじさん！？　灯台がなかったら遅かれ早かれ死ぬのよ！","ENG":"What were you thinking?! Without the Lighthouse, we're going to die anyways, just a bit later!","TWN":"你到底怎麼想的，大叔？沒有燈塔，只是死得慢一些罷了！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"큭…… 하아…….","JPN":"くっ……はぁ……","ENG":"Kgh... *Sigh...*","TWN":"咳……哈啊……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 아저씨? 왜 그래? 어디 다쳤어?","JPN":"お、おじさん？　どうしたの？　怪我したの？","ENG":"M-Mister? What's wrong? Are you hurt?","TWN":"大，大叔？你怎麼了？哪裡受傷了嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"등대가 폭발할 때…… 파편에 맞은 모양이야.","JPN":"灯台が爆発したとき……破片を食らってしまったようだ。","ENG":"I guess I was hit by shrapnel... When the Lighthouse exploded.","TWN":"爆炸的時候……我好像被碎片擊中了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"항상 운이 좋았으니……. 이런 날도……. 있을 거라고…….","JPN":"いつも運がよかったから……いつかこういう日が……来ると思ってたぜ……","ENG":"I've always been lucky... So this was... Bound to...","TWN":"我的運氣一直很好……沒想到……會有這麼一天……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"자, 잠깐! 피가……?","JPN":"ちょ、ちょっと！　血が……？","ENG":"W-wait! Blood...?","TWN":"等，等等！你在流血……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"눈 떠, 아저씨! 어서!! 일어나라고!","JPN":"目を覚まして、おじさん！　ねえ！！　起きてよ！","ENG":"Wake up, Mister! Come on! Wake up!","TWN":"你睜開眼睛啊，大叔！你快醒醒！！快站起來！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};